mapper.select:
WITH RECURSIVE cat_tree AS ( SELECT id FROM category WHERE id = #{categoryId} AND deleted_at IS NULL UNION ALL SELECT c.id FROM category c INNER JOIN cat_tree ct ON c.parent_id = ct.id WHERE c.deleted_at IS NULL )
SELECT a.id, a.title, a.course_id AS courseId, c.title AS courseTitle, a.category_id AS categoryId, cat.name AS categoryName, a.start_at AS startAt, a.end_at AS endAt, a.duration_minutes AS durationMinutes, a.total_score AS totalScore, a.pass_score AS passScore, a.max_attempts AS maxAttempts, a.status, (SELECT COUNT(DISTINCT aa.user_id) FROM assessment_attempt aa WHERE aa.assessment_id = a.id) AS participantCount, (SELECT COUNT(DISTINCT aa.user_id) FROM assessment_attempt aa WHERE aa.assessment_id = a.id AND aa.passed = 1 AND aa.status = 2) AS passedCount FROM assessment a LEFT JOIN course c ON c.id = a.course_id AND c.deleted_at IS NULL LEFT JOIN category cat ON cat.id = a.category_id AND cat.deleted_at IS NULL WHERE a.deleted_at IS NULL
AND (a.title LIKE CONCAT('%', #{keyword}, '%') OR c.title LIKE CONCAT('%', #{keyword}, '%'))
AND a.course_id = #{courseId}
AND a.category_id IN (SELECT id FROM cat_tree)
AND a.status = #{status}
AND a.start_at >= #{startFrom}
AND a.start_at <= #{startTo}
ORDER BY a.created_at DESC, a.id DESC
